"use strict";parserFactory.register("qinxiaoshuo.com",()=>new QinxiaoshuoParser);class QinxiaoshuoParser extends Parser{constructor(){super()}getChapterUrls(e){let t=[...e.querySelectorAll("div.chapters a")].map(e=>util.hyperLinkToChapter(e));return Promise.resolve(t)}findContent(e){return e.querySelector("div#chapter_content")}extractTitleImpl(e){return e.querySelector("div.book_name").textContent}extractAuthor(e){let t=e.querySelector("div.info a");return null===t?super.extractAuthor(e):t.textContent}extractLanguage(){return"cn"}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.book_info")}fetchChapter(e){return HttpClient.wrapFetch(e).then(function(t){let r=t.responseXML,o=new Set;o.add(e),o.add(e+"?xiaoshuo=1");let n=QinxiaoshuoParser.urlOfNextPageOfChapter(r,o);return QinxiaoshuoParser.fetchPagesOfChapter(r,o,n)})}static fetchPagesOfChapter(e,t,r){return null===r?Promise.resolve(e):HttpClient.wrapFetch(r).then(function(o){t.add(r),QinxiaoshuoParser.copyContentNodes(e,o.responseXML);let n=QinxiaoshuoParser.urlOfNextPageOfChapter(o.responseXML,t);return QinxiaoshuoParser.fetchPagesOfChapter(e,t,n)})}static urlOfNextPageOfChapter(e,t){let r=[...e.querySelectorAll("div.buttons a")].filter(e=>QinxiaoshuoParser.isPossibleNextPage(e,t));return 0<r.length?r[0].href:null}static isPossibleNextPage(e,t){return null!==new URL(e.href).searchParams.get("xiaoshuo")&&!t.has(e.href)}static copyContentNodes(e,t){let r=new QinxiaoshuoParser,o=r.findContent(e),n=e.createElement("div");o.appendChild(n);for(let o of r.findContent(t).childNodes){let t=e.importNode(o);n.appendChild(t)}}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll(".book_info .info, .book_info .book_name, .book_info .book_intro")]}}